import { useEffect, useState } from "react";
import BaselineChartBTC from "./chartsbtc";
import "./crypto.css";
import bookmark from "../src/assets/bookmark.png";
import bookmark2 from "../src/assets/bookmark2.png";

function Crypto() {
  const [cryptodata, setCryptodata] = useState([]);
  const [sparkline, setSparkline] = useState([]);
  const [favs, setFavs] = useState(() => new Set()); // store favourites by coin id

  useEffect(() => {
    async function fetchcoins() {
      const fetched = await fetch(
        "https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&ids=bitcoin,ethereum,binancecoin,ripple,solana,tron,dogecoin,monero"
      );
      const fetchedjson = await fetched.json();
      setCryptodata(fetchedjson);
    }

    async function fetchgraph() {
      const arr = ["BTCUSDT", "ETHUSDT", "BNBUSDT", "XRPUSDT", "SOLUSDT", "TRXUSDT", "DOGEUSDT", "XMRUSDT"];
      const response = arr.map(async (item) => {
        const res = await fetch(`https://api.binance.com/api/v3/klines?symbol=${item}&interval=1h&limit=30`);
        return await res.json();
      });

      const allresult = await Promise.all(response);

      const res = allresult.map((item) =>
        item.map((subitem) => [subitem[0], subitem[4]]) // just take time + close
      );

      setSparkline(res);
    }

    fetchcoins();
    fetchgraph();
  }, []);

  function toggleFav(coinId) {
    setFavs((prev) => {
      const next = new Set(prev);
      if (next.has(coinId)) next.delete(coinId);
      else next.add(coinId);
      return next;
    });
  }

  return (
    <>
      {cryptodata.length > 0 &&
        sparkline.length > 0 &&
        cryptodata.map((coin, index) => (
          <div className="coinRow" key={coin.id}>
            <div className="coinCell coinRank">
              <p className="coinMuted">#{coin.market_cap_rank}</p>
            </div>

            <div className="coinCell coinIdentity">
              <img className="coinLogo" src={coin.image} alt={coin.name} />
              <div className="coinNameWrap">
                <p className="coinName">{coin.name}</p>
                <p className="coinTicker">{coin.symbol.toUpperCase()}</p>
              </div>
            </div>

            <div className="coinCell coinPrice">
              <p className="coinValue">£{coin.current_price}</p>
            </div>

            <div className={"coinCell coinChange " + (coin.price_change_percentage_24h >= 0 ? "isUp" : "isDown")}>
              <p className="coinValue">{coin.price_change_percentage_24h}%</p>
            </div>

            <div className="coinCell coinChart">
              <div className="sparkWrap">
                <BaselineChartBTC sparklinedata={sparkline[index]} />
              </div>
            </div>

            <div className="coinCell coinMcap">
              <p className="coinValue">£{coin.market_cap}</p>
            </div>

            <div className="coinCell coinVol">
              <p className="coinValue">£{coin.total_volume}</p>
            </div>

            <div className="coinCell" id="coinBookmark">
              <img
                src={favs.has(coin.id) ? bookmark2 : bookmark}
                onClick={() => toggleFav(coin.id)}
                alt="bookmark"
                style={{ cursor: "pointer" }}
              />
            </div>
          </div>
        ))}
    </>
  );
}

export default Crypto;
